/* ─── Reset & Base ──────────────────────────────────────────────────────── */
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

:root {
  --font: 'Inter', system-ui, -apple-system, sans-serif;
  --bg: #050505;
  --surface: rgba(10, 10, 10, 0.85);
  --surface-opaque: #0a0a0a;
  --surface-2: rgba(20, 20, 20, 0.9);
  --border: rgba(192, 192, 192, 0.2);
  --text: #e0e0e0;
  --text-muted: #888;
  --gold: #ffbf00;
  --gold-glow: rgba(255, 191, 0, 0.4);
  --silver: #c0c0c0;
  --cyan: #00f3ff;
  --blue: #3b82f6;
  --amber: #f59e0b;
  --green: #10b981;
  --pink: #ec4899;
  --header-height: 64px;
  --glass: blur(25px);
  --panel-width: 400px;
}

html, body {
  background: var(--bg);
  color: var(--text);
  font-family: var(--font);
  height: 100%;
  overflow: hidden;
}

#root {
  height: 100%;
}

button {
  font-family: var(--font);
  cursor: pointer;
  transition: all 0.2s cubic-bezier(0.4, 0, 0.2, 1);
}

select {
  font-family: var(--font);
  appearance: none;
  cursor: pointer;
}

/* ─── Layout ───────────────────────────────────────────────────────────── */
.app-container {
  display: flex;
  height: 100dvh;
  background: var(--bg);
  overflow-x: auto;
}

.dashboard {
  flex: 1;
  display: flex;
  flex-direction: column;
  height: 100%;
  min-width: 600px;
  background: var(--bg);
  background-image: 
    radial-gradient(circle at 0% 0%, rgba(255, 191, 0, 0.02) 0%, transparent 40%),
    radial-gradient(circle at 100% 100%, rgba(255, 191, 0, 0.02) 0%, transparent 40%);
}

.dashboard__header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 16px;
  height: var(--header-height);
  background: rgba(5, 5, 5, 0.95);
  backdrop-filter: var(--glass);
  border-bottom: 1px solid var(--border);
  flex-shrink: 0;
  gap: 12px;
}

.dashboard__header-left {
  display: flex;
  align-items: center;
  gap: 12px;
  min-width: 0;
}

.dashboard__header-right {
  display: flex;
  align-items: center;
  gap: 8px;
  flex-shrink: 0;
}

.dashboard__title {
  font-size: 1.1rem;
  font-weight: 900;
  letter-spacing: 0.2em;
  color: var(--text);
  white-space: nowrap;
  text-transform: uppercase;
  background: linear-gradient(to right, #fff, var(--gold));
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
}

.dashboard__profile-trigger {
  background: var(--surface);
  border: 1px solid var(--border);
  color: var(--text);
  padding: 8px 14px;
  border-radius: 2px;
  font-size: 0.75rem;
  font-weight: 700;
  letter-spacing: 0.05em;
  cursor: pointer;
  display: flex;
  align-items: center;
  gap: 8px;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  max-width: 180px;
  text-transform: uppercase;
}

.dashboard__profile-trigger:hover {
  border-color: var(--gold);
  box-shadow: 0 0 15px var(--gold-glow);
}

.dashboard__streak {
  background: var(--surface);
  border: 1px solid var(--border);
  color: var(--gold);
  padding: 8px 14px;
  border-radius: 2px;
  font-size: 0.85rem;
  font-weight: 700;
  white-space: nowrap;
  cursor: pointer;
  transition: all 0.2s;
}

.dashboard__streak:hover {
  border-color: var(--gold);
  box-shadow: 0 0 10px var(--gold-glow);
}

.dashboard__icon-btn {
  background: var(--surface);
  border: 1px solid var(--border);
  color: var(--text);
  width: 38px;
  height: 38px;
  border-radius: 2px;
  font-size: 1.1rem;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  flex-shrink: 0;
}

.dashboard__icon-btn:hover {
  border-color: var(--gold);
  color: var(--gold);
}

.dashboard__main {
  flex: 1;
  overflow-y: auto;
  padding: 20px;
  -webkit-overflow-scrolling: touch;
}

.dashboard__view-toggle {
  display: flex;
  gap: 2px;
  margin-bottom: 20px;
  background: rgba(255,255,255,0.03);
  padding: 2px;
  border-radius: 2px;
}

/* ─── Side Panels Stack ────────────────────────────────────────────────── */
.side-panels-container {
  display: flex;
  flex-direction: row;
  height: 100%;
  flex-shrink: 0;
}

.side-panel {
  width: var(--panel-width);
  height: 100%;
  border-left: 1px solid var(--border);
  background: var(--surface-opaque);
  display: flex;
  flex-direction: column;
  position: relative;
  z-index: 10;
  overflow: hidden;
}

.side-panels-container.left-dock .side-panel {
  border-left: none;
  border-right: 1px solid var(--border);
}

.resize-handle {
  position: absolute;
  top: 0;
  bottom: 0;
  width: 6px;
  cursor: col-resize;
  z-index: 20;
  transition: background 0.2s;
}

.resize-handle:hover, .resize-handle.active {
  background: var(--gold-glow);
}

.resize-handle--left { left: 0; }
.resize-handle--right { right: 0; }

/* Mobile specific for panels */
@media (max-width: 1023px) {
  .side-panel {
    position: fixed;
    inset: 0;
    width: 100%;
    z-index: 3000;
  }

  .chat-drawer {
    height: 92vh !important;
    top: auto !important;
    bottom: 0 !important;
  }
}

/* ─── Buttons ───────────────────────────────────────────────────────────── */
.btn-review {
  display: block;
  width: 100%;
  margin-bottom: 16px;
  padding: 14px 24px;
  background: var(--gold);
  color: #000;
  border: none;
  border-radius: 2px;
  font-weight: 900;
  font-size: 0.85rem;
  letter-spacing: 0.15em;
  cursor: pointer;
  text-transform: uppercase;
  box-shadow: 0 4px 20px rgba(255, 191, 0, 0.2);
}

.btn-review:hover { 
  transform: translateY(-1px);
  box-shadow: 0 6px 25px rgba(255, 191, 0, 0.3);
}
.btn-review:disabled { opacity: 0.4; cursor: not-allowed; transform: none; }

.btn-toggle {
  flex: 1;
  padding: 10px 14px;
  background: transparent;
  color: var(--text-muted);
  border: none;
  border-radius: 2px;
  font-weight: 700;
  font-size: 0.7rem;
  letter-spacing: 0.1em;
  cursor: pointer;
  text-transform: uppercase;
}

.btn-toggle:hover { color: white; }

.btn-toggle.active {
  background: rgba(255, 191, 0, 0.1);
  color: var(--gold);
  box-shadow: inset 0 0 10px rgba(255, 191, 0, 0.1);
}

/* ─── Section Titles ────────────────────────────────────────────────────── */
.section-title {
  font-size: 0.72rem;
  font-weight: 800;
  letter-spacing: 0.2em;
  color: var(--gold);
  text-transform: uppercase;
  margin-bottom: 12px;
  display: flex;
  align-items: center;
  gap: 8px;
}

.section-title::after {
  content: '';
  flex: 1;
  height: 1px;
  background: linear-gradient(to right, var(--gold), transparent);
  opacity: 0.2;
}

/* ─── Mastery Grid ──────────────────────────────────────────────────────── */
.mastery-grid-container {
  position: relative;
  padding-bottom: 100px;
}

.grid-toolbar {
  display: flex;
  gap: 10px;
  margin-bottom: 16px;
}

.sort-select {
  flex: 1;
  padding: 10px 14px;
  background: var(--surface);
  border: 1px solid var(--border);
  color: var(--text);
  border-radius: 2px;
  font-size: 0.85rem;
  width: auto;
  backdrop-filter: var(--glass);
}

.mastery-grid__cards {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(100px, 1fr));
  gap: 10px;
}

/* ─── Vocab Cards ───────────────────────────────────────────────────────── */
.vocab-card {
  padding: 12px 10px;
  border-radius: 2px;
  border: 1px solid var(--border);
  background: var(--surface);
  backdrop-filter: var(--glass);
  user-select: none;
  cursor: pointer;
  position: relative;
  overflow: hidden;
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.vocab-card:hover {
  border-color: var(--gold);
  background: rgba(255, 191, 0, 0.05);
}

/* DO NOT ALTER STATUS COLORS per requirement */
.vocab-card--not_started  { border-left: 3px solid #374151; }
.vocab-card--introduced   { border-left: 3px solid var(--blue); }
.vocab-card--practicing   { border-left: 3px solid var(--amber); }
.vocab-card--confident    { border-left: 3px solid #16a34a; }
.vocab-card--mastered     { border-left: 3px solid var(--cyan); }

.vocab-card__word {
  font-weight: 800;
  font-size: 0.95rem;
  color: var(--text);
  word-break: break-word;
}

.vocab-card__pos {
  font-size: 0.6rem;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.05em;
  font-weight: 700;
}

/* ─── Modals ────────────────────────────────────────────────────────── */
.modal-backdrop {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.9);
  backdrop-filter: blur(12px);
  z-index: 5000;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 20px;
}

.modal-content {
  background: var(--surface-opaque);
  border: 1px solid var(--border);
  border-radius: 4px;
  width: 100%;
  max-width: 500px;
  max-height: 90vh;
  overflow-y: auto;
  position: relative;
  box-shadow: 0 20px 80px rgba(0,0,0,0.8), 0 0 40px rgba(255, 191, 0, 0.05);
}

/* ─── Side Panel Components ─────────────────────────────────────────── */
.side-panel-header {
  height: var(--header-height);
  padding: 0 16px;
  display: flex;
  align-items: center;
  border-bottom: 1px solid var(--border);
  background: rgba(5,5,5,0.95);
  backdrop-filter: var(--glass);
  position: sticky;
  top: 0;
  z-index: 10;
  flex-shrink: 0;
}

.side-panel-content {
  flex: 1;
  padding: 24px;
  overflow-y: auto;
}

.btn-back {
  background: var(--surface);
  border: 1px solid var(--border);
  color: white;
  padding: 8px 16px;
  border-radius: 2px;
  font-size: 0.7rem;
  font-weight: 900;
  display: flex;
  align-items: center;
  gap: 8px;
  letter-spacing: 0.1em;
}

.btn-back:hover {
  border-color: var(--gold);
  color: var(--gold);
}

/* ─── Drawer Styles ────────────────────────────────────────── */
.drawer-backdrop {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.7);
  backdrop-filter: blur(6px);
  z-index: 1000;
}

/* Desktop: No backdrops for drawers/panels */
@media (min-width: 1024px) {
  .drawer-backdrop {
    display: none;
  }
}

.chat-drawer {
  height: 100%;
  background: var(--surface-opaque);
  border-left: 1px solid var(--border);
  display: flex;
  flex-direction: column;
}

/* ─── Scrollbars ────────────────────────────────────────────────────────── */
::-webkit-scrollbar { width: 4px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb { background: #222; border-radius: 2px; }
::-webkit-scrollbar-thumb:hover { background: var(--gold); }

/* ─── Misc ──────────────────────────────────────────────────────────────── */
button:active { transform: scale(0.96); }

.glass-panel {
  background: var(--surface);
  backdrop-filter: var(--glass);
  border: 1px solid var(--border);
  border-radius: 2px;
  padding: 20px;
}

.neon-text-gold { color: var(--gold); text-shadow: 0 0 10px rgba(255, 191, 0, 0.3); }
.neon-border-gold { border-color: var(--gold); box-shadow: 0 0 15px rgba(255, 191, 0, 0.1); }

/* Mobile Optimizations */
@media (max-width: 768px) {
  .dashboard {
    padding: 12px 12px 80px;
  }

  .dashboard__header {
    margin-bottom: 12px;
  }

  .dashboard__title {
    font-size: 1.2rem;
  }

  .status-grid-mobile {
    display: flex !important;
    overflow-x: auto;
    padding-bottom: 8px;
    gap: 8px;
    -webkit-overflow-scrolling: touch;
    scrollbar-width: none;
    grid-template-columns: none !important;
  }

  .status-grid-mobile::-webkit-scrollbar {
    display: none;
  }

  .status-card-mobile {
    flex: 0 0 75px;
    padding: 6px 4px !important;
    min-width: 75px;
  }

  .mobile-action-row {
    flex-direction: row !important;
    gap: 6px !important;
  }

  .mobile-action-row button {
    font-size: 0.65rem !important;
    padding: 10px 4px !important;
  }

  .btn-review {
    padding: 12px 10px;
    font-size: 0.75rem;
  }
}

