.vocab-card--mastered     { border-left: 3px solid var(--cyan); }

.vocab-card__word {
  font-weight: 800;
  font-size: 0.95rem;
  color: var(--text);
  word-break: break-word;
}

.vocab-card__pos {
  font-size: 0.6rem;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.05em;
  font-weight: 700;
}

/* ─── Modals ────────────────────────────────────────────────────────── */
.modal-backdrop {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.9);
  backdrop-filter: blur(12px);
  z-index: 5000;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 20px;
}

.modal-content {
  background: var(--surface-opaque);
  border: 1px solid var(--border);
  border-radius: 4px;
  width: 100%;
  max-width: 500px;
  max-height: 90vh;
  overflow-y: auto;
  position: relative;
  box-shadow: 0 20px 80px rgba(0,0,0,0.8), 0 0 40px rgba(255, 191, 0, 0.05);
}

/* ─── Side Panel Components ─────────────────────────────────────────── */
.side-panel-header {
  height: var(--header-height);
  padding: 0 16px;
  display: flex;
  align-items: center;
  border-bottom: 1px solid var(--border);
  background: rgba(5,5,5,0.95);
  backdrop-filter: var(--glass);
  position: sticky;
  top: 0;
  z-index: 10;
  flex-shrink: 0;
}

.side-panel-content {
  flex: 1;
  padding: 24px;
  overflow-y: auto;
}

.btn-back {
  background: var(--surface);
  border: 1px solid var(--border);
  color: white;
  padding: 8px 16px;
  border-radius: 2px;
  font-size: 0.7rem;
  font-weight: 900;
  display: flex;
  align-items: center;
  gap: 8px;
  letter-spacing: 0.1em;
}

.btn-back:hover {
  border-color: var(--gold);
  color: var(--gold);
}

/* ─── Drawer Styles ────────────────────────────────────────── */
.drawer-backdrop {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.7);
  backdrop-filter: blur(6px);
  z-index: 1000;
}

/* Desktop: No backdrops for drawers/panels */
@media (min-width: 1024px) {
  .drawer-backdrop {
    display: none;
  }
}

.chat-drawer {
  height: 100%;
  background: var(--surface-opaque);
  border-left: 1px solid var(--border);
  display: flex;
  flex-direction: column;
}

/* ─── Scrollbars ────────────────────────────────────────────────────────── */
::-webkit-scrollbar { width: 4px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb { background: #222; border-radius: 2px; }
::-webkit-scrollbar-thumb:hover { background: var(--gold); }

/* ─── Misc ──────────────────────────────────────────────────────────────── */
button:active { transform: scale(0.96); }

.glass-panel {
  background: var(--surface);
  backdrop-filter: var(--glass);
  border: 1px solid var(--border);
  border-radius: 2px;
  padding: 20px;
}

.neon-text-gold { color: var(--gold); text-shadow: 0 0 10px rgba(255, 191, 0, 0.3); }
.neon-border-gold { border-color: var(--gold); box-shadow: 0 0 15px rgba(255, 191, 0, 0.1); }

/* Mobile Optimizations */
@media (max-width: 768px) {
  .dashboard {
    padding: 12px 12px 80px;
  }

  .dashboard__header {
    margin-bottom: 12px;
  }

  .dashboard__title {
    font-size: 1.2rem;
  }

  .status-grid-mobile {
    display: flex !important;
    overflow-x: auto;
    padding-bottom: 8px;
    gap: 8px;
    -webkit-overflow-scrolling: touch;
    scrollbar-width: none;
    grid-template-columns: none !important;
  }

  .status-grid-mobile::-webkit-scrollbar {
    display: none;
  }

  .status-card-mobile {
    flex: 0 0 75px;
    padding: 6px 4px !important;
    min-width: 75px;
  }

  .mobile-action-row {
    flex-direction: row !important;
    gap: 6px !important;
  }

  .mobile-action-row button {
    font-size: 0.65rem !important;
    padding: 10px 4px !important;
  }

  .btn-review {
    padding: 12px 10px;
    font-size: 0.75rem;
  }
}

